use std::collections::HashMap;

struct ServiceConfig {
    name: String,
    expected_cert: String,
}

fn build_auth_map(configs: &[ServiceConfig]) -> HashMap<String, &'static str> {
    let mut map = HashMap::new();
    for config in configs {
        map.insert(config.name.clone(), "ok_string_placeholder");
    }
    map
}

fn main() {
    let services = vec![ 
        ServiceConfig { name: String::from("auth-service"), expected_cert: String::from("abc") },
        ServiceConfig { name: String::from("user-api"), expected_cert: String::from("def") } 
    ];

    let auth_map = build_auth_map(&services);

    println!("Successfully built authentication map with {} services.", auth_map.len());
    for (service, _) in &auth_map {
        println!("Found entry for: {}", service);
    }
}
